import{_ as i,o as a,c as e,ag as n}from"./chunks/framework.uucRfDOW.js";const c=JSON.parse('{"title":"Role Hierarchy & Ranking","description":"","frontmatter":{},"headers":[],"relativePath":"hierarchy.md","filePath":"hierarchy.md"}'),t={name:"hierarchy.md"};function h(r,s,l,p,o,k){return a(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="role-hierarchy-ranking" tabindex="-1">Role Hierarchy &amp; Ranking <a class="header-anchor" href="#role-hierarchy-ranking" aria-label="Permalink to &quot;Role Hierarchy &amp; Ranking&quot;">​</a></h1><p>OmniGuard provides an easy way to manage how roles relate to each other. It uses a simple <strong>Rank System</strong> where roles are assigned a <code>sort_order</code> that determines their priority.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>In OmniGuard, a <strong>Lower Sort Order = Higher Priority</strong>.</p><ul><li><code>Admin</code> (sort_order: 1)</li><li><code>Manager</code> (sort_order: 10)</li><li><code>Staff</code> (sort_order: 50)</li><li><code>User</code> (sort_order: 100)</li></ul><p>When you check permissions, OmniGuard can look at a user&#39;s highest role (via <code>getTopRole()</code>) to help decide what they are allowed to do.</p><hr><h2 id="role-inheritance" tabindex="-1">Role Inheritance <a class="header-anchor" href="#role-inheritance" aria-label="Permalink to &quot;Role Inheritance&quot;">​</a></h2><p>OmniGuard can help you pass permissions from one role to another. For example, an Admin can automatically have all the permissions that a Manager has:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$manager </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Role</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">findByName</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Manager&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$admin </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Role</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">findByName</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Administrator&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Administrator gets all Manager permissions</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$admin</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($manager</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">permissions);</span></span></code></pre></div><p>While this is useful, OmniGuard also works great with <strong>Discovery Brain</strong> (see the Heuristics guide) which can handle most of this for you.</p><hr><h2 id="helpful-admin-override" tabindex="-1">Helpful Admin Override <a class="header-anchor" href="#helpful-admin-override" aria-label="Permalink to &quot;Helpful Admin Override&quot;">​</a></h2><p>OmniGuard provides a simple way to set a &quot;SuperUser&quot; who always passes permission checks. This is great for your own account or for maintenance tasks.</p><p>You can configure this by setting an email in your <code>.env</code>: <code>OMNIGUARD_SUPER_ADMIN_EMAIL=your@email.com</code></p><hr><h2 id="filtering-users" tabindex="-1">Filtering Users <a class="header-anchor" href="#filtering-users" aria-label="Permalink to &quot;Filtering Users&quot;">​</a></h2><p>OmniGuard makes it easy to find users based on their roles:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Find all Admins</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$admins </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> User</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">role</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Admin&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Find everyone who ISN&#39;T a Guest</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$staff </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> User</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">withoutRole</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Guest&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span></code></pre></div><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Learn how OmniGuard&#39;s brain helps automate your setup in the <strong><a href="./heuristics.html">Discovery Brain Guide</a></strong>.</p>`,22)])])}const g=i(t,[["render",h]]);export{c as __pageData,g as default};
